  { json: { name: 'Cursor',  url: 'https://cursor.com/changelog',         recipientEmail: RECIPIENT_EMAIL } },
  { json: { name: 'Replit',  url: 'https://docs.replit.com/updates',      recipientEmail: RECIPIENT_EMAIL } }
];

function extractText(html) {
  if (!html || typeof html !== 'string') return '';
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/gi, '&').replace(/&lt;/gi, '<').replace(/&gt;/gi, '>')
    .replace(/&nbsp;/gi, ' ').replace(/&#\d+;/gi, ' ').replace(/&[a-z]+;/gi, ' ')
    .replace(/\s+/g, ' ').trim();
}

const COMPETITORS = ['Lovable', 'Cursor', 'Replit'];
const URLS = [
  'https://docs.lovable.dev/changelog',
  'https://cursor.com/changelog',
  'https://docs.replit.com/updates'
];

const allItems = $input.all();
const recipientEmail = allItems[0]?.json?.recipientEmail || 'configure-email@gmail.com';

let sections = '';
for (let i = 0; i < 3; i++) {
  const raw = allItems[i]?.json?.data || allItems[i]?.json?.body || '';
  const cleaned = extractText(raw).slice(0, 5000);
  const content = cleaned.length > 150
    ? cleaned
    : `[Page returned minimal content. ${URLS[i]} may require JS rendering. Check manually.]`;
  sections += `\n\n=== ${COMPETITORS[i].toUpperCase()} (${URLS[i]}) ===\n${content}`;
}

const today = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const text = `Perform competitive intelligence analysis. Date: ${today}.${sections}`;

return [{ json: { text, date: today, sources: COMPETITORS.join(', '), recipientEmail } }];
